INSERT INTO "orbs" ("id","slug","orb_id","orb_name","known_effects","note","created_utc","modified_utc") VALUES(1,'making',1,'Making - メイキング',replace('Allows user to assign free SP to their stats. Can also assign free SP of party members, including grandchild parties.\n\nSecond effect allows user to select an orb every 100 kills. Orb choices are based on the creature killed as kill 100. It is not 100 of the same creature.','\n',char(10)),replace('This orb has only ever been shown as メイキング in the original Japanese light novel and manga to my knowledge.\n\nThis is important as the katakana spelling could be romanized as `Making`, `May King`, or `Mei King`.\n\nAll three versions have been commented on in story and all are phonetically correct to the katakana when spoken in English.\n\nWhen first shown in the JNC translation it is called "May King" and Keigo even says to himself `The monarch of spring, eh?` \n\n![Making skill card](/img/orbs/making-01.png) ![Making orb](/img/orbs/making-02.png)','\n',char(10)),'2026-05-10T23:14:19Z','2026-05-11T15:45:53Z');
INSERT INTO "orbs" ("id","slug","orb_id","orb_name","known_effects","note","created_utc","modified_utc") VALUES(2,'accelerated-growth',2,'Accelerated Growth','Unregistered Skill',NULL,'2026-05-10T23:14:19Z',NULL);
INSERT INTO "orbs" ("id","slug","orb_id","orb_name","known_effects","note","created_utc","modified_utc") VALUES(3,'agi1',3,'AGI+1','Adds 1 point to the user''s AGI stat',NULL,'2026-05-10T23:14:19Z',NULL);
INSERT INTO "orbs" ("id","slug","orb_id","orb_name","known_effects","note","created_utc","modified_utc") VALUES(4,'agihp1',4,'AGI×HP+1','Adds 1 to the default AGI to HP coefficient. It is unknown if this add 1 or 0.1 to the normal 0.1 HP coefficient for AGI.',NULL,'2026-05-10T23:14:19Z',NULL);
