INSERT INTO "orbs" ("id","slug","orb_id","orb_name","known_effects","note","created_utc","modified_utc") VALUES(33,'storage',33,'Storage','Stores objects in an extra-dimensional space. Time passes at half of real time for objects stored. Has an unknown maximum capacity, but is known to be more than 20 tons. Item can be removed from storage at a distance form the user. Items can also be removed from storage with acceleration.',NULL,'2026-05-10T23:14:19Z',NULL);
