INSERT INTO "orbs" ("id","slug","orb_id","orb_name","known_effects","note","created_utc","modified_utc") VALUES(39,'undeath',39,'Undeath','You shall inherit an eternally undying body.<br>Undead transformation (skeleton)<br>Those who violate the natural order shall receiv fitting renumeration.','Was called Undeath in volume 2 and Undying in volume 5. It is assumed it is the same orb because both were from skeletons on the 10th floor.','2026-05-10T23:14:19Z',NULL);
INSERT INTO "orbs" ("id","slug","orb_id","orb_name","known_effects","note","created_utc","modified_utc") VALUES(40,'vault',40,'Vault','Stores objects in an extra-dimensional space. Time does not pass for objects stored. Has a maximum capacity of approximately under 20 tons',NULL,'2026-05-10T23:14:19Z',NULL);
INSERT INTO "orbs" ("id","slug","orb_id","orb_name","known_effects","note","created_utc","modified_utc") VALUES(41,'water-magic',41,'Water Magic',NULL,NULL,'2026-05-10T23:14:19Z',NULL);
INSERT INTO "orbs" ("id","slug","orb_id","orb_name","known_effects","note","created_utc","modified_utc") VALUES(42,'magnetic-field-manipulation',42,'Magnetic Field Manipulation',NULL,'While we never saw the orb name officially, Iori stated it was named Magnetic Field Manipulation on her D-Card.','2026-05-10T23:14:19Z',NULL);
INSERT INTO "orbs" ("id","slug","orb_id","orb_name","known_effects","note","created_utc","modified_utc") VALUES(43,'healing-magic',43,'Healing Magic',NULL,'This orb was only mentioned by inference because of Marianne having a healing ability. The name is assumed to be Healing Magic at this time as all magic types have the word Magic in the rob name so far.','2026-05-10T23:14:19Z',NULL);
INSERT INTO "orbs" ("id","slug","orb_id","orb_name","known_effects","note","created_utc","modified_utc") VALUES(44,'light-magic',44,'Light Magic',NULL,'This orb was only mentioned in passing when Tenko was discussing the Witch of Campbell. The name is assumed to be Light Magic','2026-05-10T23:14:19Z',NULL);
INSERT INTO "orbs" ("id","slug","orb_id","orb_name","known_effects","note","created_utc","modified_utc") VALUES(45,'agihp2',45,'AGI×HP+2','Adds 2 to the default AGI to HP coefficient. It is unknown if this adds 2 or 0.2 to the normal 0.1 HP coefficient for AGI.','Never seen dropped, but was mentioned by Miyoshi when discussing dud orbs. Was named then as AGIxH+2, but making displayed the +1 as HP, so this was standardized to match.','2026-05-10T23:14:19Z',NULL);
