INSERT INTO "pending_submissions" ("id","submitted_by","submitted_at","entity_type","entity_id","operation","proposed_data","status","reviewed_by","reviewed_at","admin_note") VALUES(25,1,'2026-05-11T15:43:38Z','orb',1,'update',replace('{\n  "orb_name": "Making - メイキング",\n  "known_effects": "Allows user to assign free SP to their stats. Can also assign free SP of part members, including grandchild parties.\n\nSecond effect allows user to select an orb every 100 kills. Orb choices are based on the creature killed as kill 100. It is not 100 of the same creature.",\n  "note": "This orb has only ever been shown as メイキング in the original Japanese light novel and manga to my knowledge.\nThis is important as the katakana spelling could be romanized as `Making`, `May King`, or `Mei King`.\n\nWhen first show in the JNC translation it is called \"May King\" and Keigo even say to himself `The monarch of spring, eh?`\n\nAll three versions have been commented on in story and all are phonetically correct to the katakana when spoken in English.\n\n![Making skill card](/img/orbs/making-01.png) ![Making orb](/img/orbs/making-02.png)"\n}','\n',char(10)),'rejected',1,'2026-05-11T15:44:36Z','not correct.');
INSERT INTO "pending_submissions" ("id","submitted_by","submitted_at","entity_type","entity_id","operation","proposed_data","status","reviewed_by","reviewed_at","admin_note") VALUES(26,1,'2026-05-11T15:45:34Z','orb',1,'update',replace('{\n  "orb_name": "Making - メイキング",\n  "known_effects": "Allows user to assign free SP to their stats. Can also assign free SP of party members, including grandchild parties.\n\nSecond effect allows user to select an orb every 100 kills. Orb choices are based on the creature killed as kill 100. It is not 100 of the same creature.",\n  "note": "This orb has only ever been shown as メイキング in the original Japanese light novel and manga to my knowledge.\n\nThis is important as the katakana spelling could be romanized as `Making`, `May King`, or `Mei King`.\n\nAll three versions have been commented on in story and all are phonetically correct to the katakana when spoken in English.\n\nWhen first shown in the JNC translation it is called \"May King\" and Keigo even says to himself `The monarch of spring, eh?` \n\n![Making skill card](/img/orbs/making-01.png) ![Making orb](/img/orbs/making-02.png)"\n}','\n',char(10)),'approved',1,'2026-05-11T15:45:54Z','');
